    61	// mimeTypeFromPath guesses the MIME type from the file extension.
    62	func mimeTypeFromPath(path string) string {
    63		ext := filepath.Ext(path)
    64		if ext == "" {
    65			return "application/octet-stream"
    66		}
    67		mt := mime.TypeByExtension(ext)
    68		if mt == "" {
    69			return "application/octet-stream"
    70		}
    71		return mt
    72	}
