    38	func (r *webhookRouter) webhookRoute() (string, http.Handler) {
    39		r.mu.Lock()
    40		defer r.mu.Unlock()
    41		if !r.routeHandled {
    42			r.routeHandled = true
    43			return webhookPath, r
    44		}
    45		return "", nil
    46	}
