    48	// ServeHTTP is the shared handler for all Facebook page webhooks.
    49	// Routes each entry to the matching channel instance by page_id.
    50	//
    51	// Multi-Meta-App support: all registered page secrets are collected and tried in order.
    52	// A payload is accepted if its signature matches any known app_secret. In the common
    53	// case (single Meta App) there is exactly one secret and behavior is unchanged.
    54	func (r *webhookRouter) ServeHTTP(w http.ResponseWriter, req *http.Request) {
    55		r.mu.RLock()
    56		var primarySecret, verifyToken string
    57		var extraSecrets []string
    58		seenSecrets := make(map[string]bool)
    59		for _, ch := range r.instances {
    60			s := ch.webhookH.appSecret
    61			if primarySecret == "" {
    62				primarySecret = s
    63				verifyToken = ch.webhookH.verifyToken
    64				seenSecrets[s] = true
    65			} else if !seenSecrets[s] {
    66				extraSecrets = append(extraSecrets, s)
    67				seenSecrets[s] = true
    68			}
    69		}
    70		r.mu.RUnlock()
    71	
    72		if primarySecret == "" {
    73			// No instances registered yet.
    74			w.WriteHeader(http.StatusOK)
    75			return
    76		}
    77	
    78		if len(extraSecrets) > 0 {
    79			slog.Warn("security.facebook_multi_meta_app",
    80				"extra_app_count", len(extraSecrets),
    81				"note", "multiple Meta App secrets registered; payloads verified against all known secrets")
    82		}
    83	
    84		routingWH := &WebhookHandler{
    85			appSecret:    primarySecret,
    86			verifyToken:  verifyToken,
    87			extraSecrets: extraSecrets,
    88		}
    89		routingWH.onComment = func(entry WebhookEntry, change ChangeValue) {
    90			r.mu.RLock()
    91			target := r.instances[entry.ID]
    92			r.mu.RUnlock()
    93			if target != nil {
    94				target.handleCommentEvent(entry, change)
