   277	// logRateLimit parses the X-Business-Use-Case-Usage header and warns when approaching limits.
   278	func (g *GraphClient) logRateLimit(resp *http.Response) {
   279		usage := resp.Header.Get("X-Business-Use-Case-Usage")
   280		if usage == "" {
   281			return
   282		}
   283		var parsed map[string][]struct {
   284			CallCount int `json:"call_count"`
   285		}
   286		if err := json.Unmarshal([]byte(usage), &parsed); err != nil {
   287			return
   288		}
   289		for _, entries := range parsed {
   290			for _, e := range entries {
   291				if e.CallCount >= 95 {
   292					slog.Warn("facebook: rate limit critical", "call_count_pct", e.CallCount, "page_id", g.pageID)
   293				} else if e.CallCount >= 80 {
   294					slog.Warn("facebook: rate limit warning", "call_count_pct", e.CallCount, "page_id", g.pageID)
   295				}
   296			}
   297		}
   298	}
