   300	// parseRetryAfter extracts the Retry-After header, capped at maxRetryAfterSec.
   301	func parseRetryAfter(resp *http.Response) time.Duration {
   302		val := resp.Header.Get("Retry-After")
   303		if val == "" {
   304			return 5 * time.Second
   305		}
   306		secs, err := strconv.Atoi(val)
   307		if err != nil || secs <= 0 {
   308			return 5 * time.Second
   309		}
   310		if secs > maxRetryAfterSec {
   311			secs = maxRetryAfterSec
   312		}
   313		return time.Duration(secs) * time.Second
   314	}
