   148	// telegramAPIDescRe extracts the human-readable description from Telegram Bot API errors.
   149	// Example: `telego: sendPhoto: api: 400 "Bad Request: not enough rights to send photos to the chat"`
   150	//
   151	//	→ "not enough rights to send photos to the chat"
   152	var telegramAPIDescRe = regexp.MustCompile(`"Bad Request:\s*(.+?)"`)
   153	
   154	// formatChannelSendError converts a channel.Send error into a user-friendly message.
   155	// Never exposes raw library/HTTP details.
   156	func formatChannelSendError(err error) string {
   157		raw := err.Error()
   158		lower := strings.ToLower(raw)
   159	
   160		// Telegram "Bad Request: <description>" — extract description
   161		if m := telegramAPIDescRe.FindStringSubmatch(raw); len(m) == 2 {
   162			return fmt.Sprintf("⚠️ Send failed: %s", m[1])
   163		}
   164	
   165		// Common Telegram API errors (non-Bad Request)
   166		switch {
   167		case strings.Contains(lower, "not enough rights"):
   168			return "⚠️ Send failed: bot doesn't have permission to send this type of message."
   169		case strings.Contains(lower, "chat not found"):
   170			return "⚠️ Send failed: chat not found."
   171		case strings.Contains(lower, "bot was blocked"):
   172			return "⚠️ Send failed: bot was blocked by the user."
   173		case strings.Contains(lower, "user is deactivated"):
   174			return "⚠️ Send failed: user account is deactivated."
   175		case strings.Contains(lower, "too many requests") || strings.Contains(lower, "flood"):
   176			return "⚠️ Send failed: rate limited by Telegram. Please try again later."
   177		case strings.Contains(lower, "file is too big") || strings.Contains(lower, "wrong file"):
   178			return "⚠️ Send failed: file is too large or invalid for Telegram."
   179		}
