package pancake

import (
	"context"
	"sync"
	"time"

	"golang.org/x/sync/singleflight"
)

const defaultPostCacheTTL = 15 * time.Minute

// postCacheEntry holds a cached posts list with its expiry time.
type postCacheEntry struct {
	posts     []PancakePost
	postByID  map[string]*PancakePost // fast lookup by post ID
	expiresAt time.Time
}

// PostFetcher fetches and caches Pancake post content.
// singleflight prevents redundant concurrent API calls for the same page's posts
// (cache stampede on viral posts receiving many comments simultaneously).
//
// Unlike Facebook's per-post Graph API, Pancake requires listing all page posts.
// The singleflight key is "posts" (not per-postID) because the underlying
// API call returns all posts at once.
type PostFetcher struct {
	apiClient *APIClient
	cacheTTL  time.Duration
	cache     sync.Map          // "posts"(string) → *postCacheEntry
	sfGroup   singleflight.Group
}

// NewPostFetcher creates a PostFetcher with the given cache TTL string (e.g. "15m").
// Falls back to defaultPostCacheTTL if the string is empty or unparseable.
func NewPostFetcher(client *APIClient, cacheTTLStr string) *PostFetcher {
	ttl := defaultPostCacheTTL
	if cacheTTLStr != "" {
		if d, err := time.ParseDuration(cacheTTLStr); err == nil && d > 0 {
			ttl = d
		}
	}
	return &PostFetcher{
		apiClient: client,
		cacheTTL:  ttl,
	}
}

// GetPost returns the post for postID, using cache when fresh.
// Concurrent callers share one inflight request via singleflight key "posts".
func (pf *PostFetcher) GetPost(ctx context.Context, postID string) (*PancakePost, error) {
	if postID == "" {
		return nil, nil
	}

	// Check cache first — fast path.
	if v, ok := pf.cache.Load("posts"); ok {
		entry := v.(*postCacheEntry)
		if time.Now().Before(entry.expiresAt) {
			return entry.postByID[postID], nil
		}
		pf.cache.Delete("posts")
	}

	// Coalesce concurrent fetches under the "posts" key.
	val, err, _ := pf.sfGroup.Do("posts", func() (any, error) {
		// Re-check cache inside the singleflight call.
		if v, ok := pf.cache.Load("posts"); ok {
			entry := v.(*postCacheEntry)
			if time.Now().Before(entry.expiresAt) {
				return entry, nil
			}
		}
		posts, err := pf.apiClient.ListPosts(ctx)
		if err != nil {
			return nil, err
		}
		byID := make(map[string]*PancakePost, len(posts))
		for i := range posts {
			byID[posts[i].ID] = &posts[i]
		}
		entry := &postCacheEntry{
			posts:     posts,
			postByID:  byID,
			expiresAt: time.Now().Add(pf.cacheTTL),
		}
		pf.cache.Store("posts", entry)
		return entry, nil
	})
	if err != nil {
		return nil, err
	}
	if val == nil {
		return nil, nil
	}
	entry := val.(*postCacheEntry)
	return entry.postByID[postID], nil
}

