package pancake

import (
	"fmt"
	"log/slog"
	"strings"

	"github.com/nextlevelbuilder/goclaw/internal/channels"
)

// handleCommentEvent processes a COMMENT webhook event from the Pancake platform.
func (ch *Channel) handleCommentEvent(data MessagingData) {
	// Feature gate: silently drop COMMENT events when comment_reply is not enabled.
	if !ch.config.Features.CommentReply {
		return
	}

	// Self-reply prevention: skip comments posted by the page itself.
	if data.Message.SenderID == ch.pageID {
		slog.Info("pancake: skipping own page comment",
			"page_id", ch.pageID,
			"sender_id", data.Message.SenderID)
		return
	}

	// Dedup: Pancake may deliver the same event more than once.
	var dedupKey string
	if data.Message.ID != "" {
		dedupKey = fmt.Sprintf("comment:%s", data.Message.ID)
		if ch.isDup(dedupKey) {
			slog.Info("pancake: duplicate comment event skipped", "msg_id", data.Message.ID)
			return
		}
	}

	if data.Message.SenderID == "" {
		slog.Warn("pancake: comment missing sender_id, skipping", "msg_id", data.Message.ID)
		return
	}

	// Sender name: prefer message-level sender, fall back to conversation-level.
	senderName := data.Message.SenderName
	if senderName == "" {
		senderName = data.Message.SenderName // already set from webhook parsing
	}

	// Keyword filter: when filter mode is "keyword", only process comments containing
	// at least one of the configured keywords.
	if ch.config.CommentReplyOptions.Filter == "keyword" && len(ch.config.CommentReplyOptions.Keywords) > 0 {
		lowerContent := strings.ToLower(data.Message.Content)
		matched := false
		for _, kw := range ch.config.CommentReplyOptions.Keywords {
			if strings.Contains(lowerContent, strings.ToLower(kw)) {
				matched = true
				break
			}
		}
		if !matched {
			slog.Debug("pancake: comment filtered by keyword",
				"msg_id", data.Message.ID,
				"keywords", ch.config.CommentReplyOptions.Keywords)
			return
		}
	}

	// Build message content — optionally enriched with post context.
	content := ch.buildCommentContent(data)

	// ChatID: use conversation ID as the chat routing identifier.
	chatID := data.ConversationID

	metadata := map[string]string{
		"pancake_mode":      "comment",
		"conversation_type": data.Type,
		"platform":          data.Platform,
		"conversation_id":   data.ConversationID,
		"message_id":        dedupKey,
		"comment_id":        data.Message.ID,
		"display_name":      channels.SanitizeDisplayName(senderName),
		"page_name":         ch.pageName,
		"sender_id":         data.Message.SenderID,
	}

	ch.HandleMessage(
		data.Message.SenderID,
		chatID,
		content,
		nil,
		metadata,
		"direct",
	)

	slog.Debug("pancake: comment event published to bus",
		"page_id", ch.pageID,
		"conv_id", data.ConversationID,
		"sender_id", data.Message.SenderID,
		"platform", data.Platform,
		"msg_id", data.Message.ID,
		"channel_name", ch.Name(),
	)
}

// buildCommentContent assembles the comment text, optionally prepending post context.
func (ch *Channel) buildCommentContent(data MessagingData) string {
	var parts []string

	// Optional post context enrichment.
	if ch.config.CommentReplyOptions.IncludePostContext {
		if post, err := ch.postFetcher.GetPost(ch.stopCtx, data.ConversationID); err == nil && post != nil {
			msg := post.Message
			if msg == "" {
				msg = post.Story
			}
			if msg != "" {
				parts = append(parts, "[Bài đăng] "+msg)
			}
		}
	}

	if data.Message.Content != "" {
		parts = append(parts, stripHTML(data.Message.Content))
	}

	for _, att := range data.Message.Attachments {
		if att.URL != "" {
			parts = append(parts, att.URL)
		}
	}

	body := strings.Join(parts, "\n")

	senderID := data.Message.SenderID
	if senderID != "" {
		prefix := fmt.Sprintf("[From: %s (%s)]", senderID, senderName)
		if body != "" {
			return prefix + " " + body
		}
		return prefix
	}
	return body
}

