// sendCommentReply delivers an outbound message as a comment reply.
func (ch *Channel) sendCommentReply(ctx context.Context, msg bus.OutboundMessage) error {
	commentID := msg.Metadata["comment_id"]
	if commentID == "" {
		return fmt.Errorf("pancake: comment_id missing in outbound metadata")
	}

	text := FormatOutbound(msg.Content, ch.platform)

	if err := ch.apiClient.ReplyComment(ctx, commentID, text); err != nil {
		ch.handleAPIError(err)
		return err
	}

	// First inbox: send a one-time DM to the commenter via private_reply.
	if ch.config.Features.FirstInbox {
		senderID := msg.Metadata["sender_id"]
		if senderID != "" {
			ch.sendFirstInbox(ctx, msg.ChatID, senderID)
		}
	}

	return nil
}

// sendFirstInbox sends a one-time private DM after a comment reply (best-effort).
func (ch *Channel) sendFirstInbox(ctx context.Context, conversationID, senderID string) {
	if _, alreadySent := ch.firstInboxSent.LoadOrStore(senderID, struct{}{}); alreadySent {
